INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'aquarium-components',
'aquarium-components',
'مكونات حوض البحر الأحمر: الدليل الشامل',
'تعرف على كل مكون أساسي في حوض المياه المالحة — من القواعد الحيوية إلى أجهزة التصفية — مشروحاً بلغة بسيطة لمن يبدأ رحلته مع البحرية.',
E'## لماذا يختلف حوض المياه المالحة؟\n\nحوض المياه المالحة ليس مجرد "حوض عادي بملح". بيئة الشعاب المرجانية من أكثر البيئات تعقيداً على كرة الأرض، وإعادة إنشائها في المنزل يحتاج إلى فهم كل عنصر وسبب وجوده.\n\n---\n\n## ١. الهيكل الأساسي: الحوض والقاعدة\n\n**الحوض** هو البداية — يُصنع عادةً من الزجاج المقوّى (Low-Iron) أو الأكريليك. الحجم المثالي للمبتدئ: **200–400 لتر**، لأن الحجم الكبير يُعطيك هامشاً أوسع لتصحيح الأخطاء.\n\n**القاعدة (Cabinet)** تحمل الحوض وتخفي المعدات الثانوية. يجب أن تتحمل وزن الماء (1 لتر = 1 كيلو تقريباً) + الصخور + الزجاج.\n\n---\n\n## ٢. نظام التصفية: قلب الحوض\n\n### Sump (الحوض الثانوي)\n\nالـ Sump هو حوض صغير أسفل الحوض الرئيسي يضم معظم المعدات. فوائده:\n- زيادة حجم الماء الكلي (= استقرار أكبر)\n- إخفاء المعدات عن العرض\n- مكان لتحسين تهوية الماء\n\n### Skimmer (فارز البروتين)\n\nالـ Skimmer يُزيل المواد العضوية **قبل** أن تتحلل إلى نترات. يعمل بفقاعات هواء دقيقة تلتقط الجزيئات الدهنية والبروتينية وترفعها إلى كوب جمع.\n\n> **نصيحة:** ابحث عن Skimmer مُرشَّح لضعف حجم حوضك على الأقل. الـ Reefer Skimmer 300 (PSK 600) AC مناسب لأحواض حتى 600 لتر.\n\n### الفلتر الميكانيكي\n\n**Sock / Bag فلتر** (كيس من القماش الدقيق) يمسك الجزيئات الكبيرة. الـ 225 micron Felt filter bag مثالي كبداية — ينظّف بالغسيل البسيط.\n\n---\n\n## ٣. الحركة: المضخات\n\n### Return Pump (مضخة الإرجاع)\n\nترفع الماء من الـ Sump إلى الحوض الرئيسي. قوتها تُحدد معدل تبادل الماء. الـ ReefRun G2 12000 توفر ضخاً قوياً مع التحكم الرقمي.\n\n### Wavemaker (مولّد التيار)\n\nيحاكي حركة الموج الطبيعية. ضروري لـ:\n- توصيل الغذاء للمرجان\n- منع البقع الراكدة\n- تهوية الماء\n\n---\n\n## ٤. الإضاءة\n\nللمرجان الضوئي (LPS / SPS) تحتاج إضاءة PAR عالية. للأسماك فقط — الإضاءة العادية كافية. أنواع الإضاءة الحديثة: LED كاملة الطيف مع تحكم في شدة الضوء وألوانه.\n\n---\n\n## ٥. التدفئة والتبريد\n\n**الهيتر:** يحافظ على 25–26°C. استخدم هيترين لنصف القدرة المطلوبة لكل منهما — إذا عطل أحدهما لا يُحرق الحوض.\n\n**الكيلر (Chiller):** ضروري في المناطق الحارة لمنع ارتفاع الحرارة فوق 28°C.\n\n---\n\n## ٦. اختبار الماء والتحكم\n\n**Test Kits** دورية: الأمونيا، النترات، النتريت، KH، كالسيوم، مغنيسيوم، الملوحة.\n\n**ATO (Auto Top-Off):** يُعوّض الماء المتبخر تلقائياً للحفاظ على ثبات الملوحة.\n\n**Dosing Pump:** يُضيف محاليل KH والكالسيوم والمغنيسيوم بجرعات دقيقة يومياً.\n\n---\n\n## خلاصة قائمة المكونات\n\n| المكون | الوظيفة | الأولوية |\n|--------|---------|----------|\n| الحوض + القاعدة | الهيكل | أساسي |\n| Sump | مركز التصفية | أساسي |\n| Skimmer | إزالة العضويات | أساسي |\n| Return Pump | تدوير الماء | أساسي |\n| Wavemaker | الحركة | أساسي |\n| Heater/Chiller | التحكم بالحرارة | أساسي |\n| Lighting | الضوء للمرجان | حسب النظام |\n| ATO | استقرار الملوحة | مهم جداً |\n| Dosing Pump | جرعات الكيمياء | متقدم |\n\n---\n\n*بقلم زيد العكيلي*',
'معدات',
'["معدات","مكونات","skimmer","sump","مبتدئين"]',
'["saltwater-preparation","water-chemistry"]',
'[{"display_text":"225 micron Felt filter bag","product_name":"225 micron Felt filter bag 7 inch x 32 inch For 4 inch sock"},{"display_text":"Reefer Skimmer 300 (PSK 600) AC","product_name":"Reefer Skimmer 300 (PSK 600) AC"},{"display_text":"ReefRun G2 12000","product_name":"ReefRun G2 12000"}]',
'',
'مكونات حوض البحر الأحمر: الدليل الشامل',
'تعرف على كل مكون أساسي في حوض المياه المالحة من القواعد الحيوية إلى أجهزة التصفية',
false, 1,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'saltwater-preparation',
'saltwater-preparation',
'تحضير ماء البحر الصناعي: الخطوات الصحيحة',
'كل ما تحتاج معرفته لتحضير ماء بحر مثالي لحوضك — من اختيار الملح إلى قياس الكثافة والملوحة بدقة.',
E'## لماذا يهم تحضير الماء؟\n\nالماء هو الأساس الذي يحيا فيه كل شيء في حوضك. ماء سيئ التحضير = مشاكل لا نهاية لها.\n\n---\n\n## ١. اختيار الملح\n\nليس كل ملح مناسباً لحوض البحر. ابحث عن ملح مُصمَّم خصيصاً للحياة البحرية مع:\n- نسب Ca / KH / Mg متوازنة ومناسبة للمرجان\n- خلو من المعادن الثقيلة\n- ثبات تركيبة الدُفعة من الدُفعة\n\n> **الخيار الموصى به:** Coral Pro Salt 22kg — مُصنَّع خصيصاً لأحواض الشعاب بملوحة جاهزة 35 ppt وعناصر مثالية للنمو.\n\n---\n\n## ٢. مصدر الماء\n\n**ماء RO/DI (Reverse Osmosis + Deionization)** هو المعيار الذهبي:\n- يُزيل الكلور والكلورامين\n- يُزيل السيليكات (مصدر الطحالب البنية)\n- يُزيل النترات والفوسفات المسبقة\n- TDS يجب أن يكون **0 ppm**\n\nلا تستخدم ماء الصنبور مباشرةً ولا ماء الشرب المعبأ.\n\n---\n\n## ٣. خطوات التحضير\n\n**أ. اختبر ماء RO/DI:** تأكد من TDS = 0 ppm.\n\n**ب. أضف الملح تدريجياً:** لا تعكس الترتيب — الملح في الماء وليس الماء في الملح.\n\n**ج. حرّك جيداً:** استخدم مضخة صغيرة لمدة 24 ساعة على الأقل للذوبان الكامل.\n\n**د. اقرأ الملوحة:** استخدم Salinity Refractometer للقياس الدقيق. الهدف: **1.025–1.026** كثافة نوعية (أو 35 ppt).\n\n**هـ. تحقق من الحرارة:** اجعل الماء الجديد بنفس حرارة الحوض قبل الإضافة (25–26°C).\n\n---\n\n## ٤. كمية الملح\n\nكقاعدة عامة: **35–36 غرام ملح لكل لتر ماء RO/DI** للوصول إلى 1.025.\n\nلكن الأدق: اتبع تعليمات الملح الذي تستخدمه، ثم عدّل بالقياس.\n\n---\n\n## ٥. تبديل الماء الأسبوعي\n\nابدل **10–15%** من حجم الحوض أسبوعياً. هذا:\n- يُجدد العناصر الأثرية\n- يُخفف النترات والفوسفات\n- يُعوّض ما استهلكه المرجان\n\n> :tip: حضّر دائماً كمية إضافية جاهزة للطوارئ.\n\n---\n\n## ٦. أخطاء شائعة\n\n- **إضافة ماء غير جاهز مباشرةً:** يُصدم الأسماك بفروق الملوحة المفاجئة\n- **قياس الكثافة بعود الملوحة رخيص الثمن:** غير دقيق، استبدله بريفراكتومتر\n- **تجاهل درجة الحرارة:** فرق 2°C يُسبب ضغطاً على الأسماك والمرجان\n\n---\n\n*بقلم زيد العكيلي*',
'مياه',
'["ملح","RO","ملوحة","تحضير","مبتدئين"]',
'["aquarium-components","water-chemistry"]',
'[{"display_text":"Coral Pro Salt 22kg","product_name":"Coral Pro Salt 22kg"},{"display_text":"Salinity Refractometer","product_name":"Salinity Refractometer"}]',
'',
'تحضير ماء البحر الصناعي: الخطوات الصحيحة',
'تعرف على كيفية تحضير ماء بحر مثالي لحوضك من اختيار الملح إلى قياس الملوحة',
false, 2,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'dry-rock',
'dry-rock',
'الصخر الجاف (Dry Rock): الأساس النظيف لحوضك',
'الصخر الجاف هو خيار المبتدئين الذكي — يُقدم قاعدة تصفية بيولوجية ممتازة دون أن يُدخل آفات أو مشاكل إلى حوضك.',
E'## ما هو الصخر الجاف؟\n\nالصخر الجاف (Dry Rock) هو صخر بحري طبيعي أو مصنوع جُفِّف تماماً، مما يعني:\n- **لا حياة عليه** عند الشراء — لا طحالب، لا آفات، لا فطريات\n- **مسامي للغاية** — يوفر مساحة هائلة للبكتيريا المفيدة\n- **آمن ومتحكم به** — تبدأ من صفحة بيضاء\n\n---\n\n## الفرق بين الصخر الجاف والصخر الحي\n\n| الصخر الجاف | الصخر الحي |\n|-------------|------------|\n| رخيص | غالٍ |\n| نظيف تماماً | يحمل كائنات مفيدة وضارة |\n| يحتاج وقتاً أطول للنضج | يُسرّع النضج |\n| لا خطر من الآفات | خطر الآفات (فطريات، نجم القرنفل، إلخ) |\n| مثالي للمبتدئ | مثالي عند الثقة والخبرة |\n\n---\n\n## أنواع الصخر الجاف\n\n### ١. Pukani / Tonga (طبيعي جاف)\nمسامي جداً، وزن خفيف، شكل طبيعي جميل. الأفضل للمظهر الطبيعي.\n\n### ٢. Marco Rock (مصنوع)\nمصنوع من مواد بحرية مُعاد تدويرها، أشكال موحدة، سعر منخفض.\n\n### ٣. Reef Saver\nمسامي للغاية، ناصع البياض، يتحول للون الطبيعي مع الوقت.\n\n---\n\n## كمية الصخر المطلوبة\n\nالمعيار القديم كان "نصف كيلو لكل لتر"، لكن الأدق اليوم:\n- **الكمية الكافية لبناء هيكل جميل يسمح بالحركة**\n- لا تملأ الحوض بالصخر — الأسماك تحتاج مساحة للسباحة\n\n---\n\n## خطوات التجهيز قبل الوضع في الحوض\n\n**١. النقع في ماء RO:** 1–2 أسبوع لإزالة الفوسفات المحاصرة في الصخر.\n\n**٢. الخبز (Curing):** بعض الأشخاص يغلون الصخر الجاف أو يضعونه في الشمس لضمان عدم وجود مواد عضوية.\n\n**٣. التصميم خارج الحوض:** رتّب الصخور على طاولة أولاً، التقط صوراً، ثم انقلها.\n\n---\n\n## بناء الهيكل الصحيح\n\n- **لا تضع الصخور ملتصقة بجدار الحوض** — الحركة والبكتيريا تحتاج فراغات\n- **ارفع الصخور عن القاع** — اتركها على حوامل بلاستيكية أو Egg Crate\n- **الثبات أولاً:** استخدم Two Little Fishies Aquastik أو ملاط شعاب مرجانية لتثبيت الطبقات\n\n---\n\n## المدة حتى النضج\n\nمع الصخر الجاف وحده: **8–12 أسبوعاً** للنضج الكامل.\nمع إضافة كمية صغيرة من صخر حي أو بكتيريا جاهزة: **4–6 أسابيع**.\n\n---\n\n*بقلم زيد العكيلي*',
'إعداد',
'["صخر","dry rock","تصفية بيولوجية","إعداد","نضج"]',
'["live-rock","bacteria","aquarium-components"]',
'[]',
'',
'الصخر الجاف Dry Rock: الأساس النظيف لحوضك',
'اكتشف كيف يُقدم الصخر الجاف قاعدة تصفية بيولوجية ممتازة دون آفات أو مشاكل',
false, 3,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'live-rock',
'live-rock',
'الصخر الحي (Live Rock): كنز بيولوجي أم بوابة مشاكل؟',
'الصخر الحي يحمل معه بيئة حيوية كاملة — مليئة بالبكتيريا المفيدة والكائنات الصغيرة، لكنه قد يُدخل آفات غير مرغوب فيها. اعرف كيف تستفيد منه بأمان.',
E'## ما هو الصخر الحي؟\n\nالصخر الحي (Live Rock) هو صخر بحري مأخوذ من الشعاب المرجانية أو مُزرَّع صناعياً، محتفظاً بحياته الدقيقة الكاملة:\n- بكتيريا مُنيترة جاهزة\n- كائنات صغيرة (copepods، أمفيبودات)\n- طحالب مفيدة وأحياناً ضارة\n- أحياناً: نجم القرنفل، بلحيات الصخر، ديدان\n\n---\n\n## مزايا الصخر الحي\n\n**١. يُسرّع النضج البيولوجي بشكل كبير**\nالبكتيريا جاهزة ونشطة — يمكن تقليص وقت النضج من 8 أسابيع إلى 2–3 أسابيع.\n\n**٢. يُدخل حياة مفيدة**\nالـ Copepods غذاء طبيعي للأسماك. الكائنات الصغيرة تُساعد في تنظيف القاع.\n\n**٣. مظهر طبيعي فوري**\nيبدو "حياً" من اليوم الأول مع ألوانه الطبيعية.\n\n---\n\n## مخاطر الصخر الحي\n\n### الآفات المحتملة:\n\n| الآفة | الضرر | الصعوبة |\n|-------|-------|----------|\n| نجم القرنفل (Aiptasia) | يلسع ويتكاثر بسرعة | متوسطة |\n| نجم أوركيد (Majano) | يلسع ويغزو الحجارة | صعبة |\n| بلح البحر (Vermetid Snails) | خيوط تُزعج المرجان | صعبة |\n| Bubble Algae | تنتشر بسرعة | سهلة |\n| Bristle Worms | معظمها غير ضار | |\n\n---\n\n## كيف تتعامل مع الصخر الحي بأمان؟\n\n**الخيار الأول: عزل (Quarantine)**\nضع الصخر الحي في حوض عزل لمدة 4–6 أسابيع. راقبه يومياً وأزل أي آفة تظهر.\n\n**الخيار الثاني: الدمج الذكي**\n8 أجزاء صخر جاف + 1 جزء صخر حي. تحصل على البكتيريا المفيدة مع حد أدنى من خطر الآفات.\n\n**الخيار الثالث: الصخر الحي المزروع**\nيُزرَّع في بيئة خاضعة للتحكم، خالٍ من الآفات، لكن بسعر أعلى.\n\n---\n\n## Curing الصخر الحي\n\nقبل وضع الصخر الحي في حوضك:\n1. انقعه في ماء بحر جديد (لا ماء حوض)\n2. غيّر الماء يومياً\n3. أزل أي جزء ميت برائحة كريهة\n4. استمر 2–4 أسابيع حتى تختفي الرائحة تماماً\n\n---\n\n## هل تحتاج صخراً حياً؟\n\nإذا كان عندك صبر وبكتيريا جاهزة — يمكنك الاستغناء عن الصخر الحي تماماً. الصخر الجاف + بكتيريا جاهزة = نتيجة ممتازة وأكثر أماناً للمبتدئ.\n\n---\n\n*بقلم زيد العكيلي*',
'إعداد',
'["صخر حي","live rock","نضج","آفات","بكتيريا"]',
'["dry-rock","bacteria","aquarium-components"]',
'[]',
'',
'الصخر الحي Live Rock: كنز بيولوجي أم بوابة مشاكل؟',
'تعرف على مزايا ومخاطر الصخر الحي وكيف تستخدمه بأمان في حوضك البحري',
false, 4,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'sand',
'sand',
'رمل حوض البحر: ما تحتاج معرفته قبل الشراء',
'الرمل ليس مجرد زينة — إنه نظام بيولوجي حي يُساهم في التصفية. تعرف على أنواعه وكمياته وطريقة إعداده الصحيحة.',
E'## هل الرمل ضروري؟\n\nلا — يمكنك تشغيل حوض بدون رمل (Bare Bottom). لكن الرمل يُضيف:\n- بيئة للبكتيريا اللاهوائية (تُحوّل النترات إلى نيتروجين)\n- مكان للكائنات القاعية والأسماك التي تحفر\n- مظهر طبيعي وجميل\n\n---\n\n## أنواع الرمل\n\n### ١. Aragonite (أراغونيت)\nالأفضل للأحواض البحرية:\n- يُساعد في استقرار pH\n- يُذوَّب ببطء محرراً الكالسيوم\n- من أصل بحري طبيعي\n\n### ٢. Crushed Coral\nحبيبات أكبر، يُحبس الملوثات بين الحبيبات ويُصعب التنظيف.\n\n### ٣. رمل طبيعي (Silica)\nغير مناسب — يرفع نسبة السيليكات مسبباً طحالب بنية.\n\n---\n\n## حجم الحبيبات\n\n| الحجم | الاستخدام |\n|-------|----------|\n| 0.5–1.5 mm (ناعم) | قاع حي (DSB) — للتصفية البيولوجية العميقة |\n| 1.5–3 mm (متوسط) | الأكثر شيوعاً، سهل التنظيف |\n| 3–5 mm (خشن) | أقل فائدة بيولوجية، أصعب تنظيفاً |\n\n---\n\n## سُمك طبقة الرمل\n\n**SSB (Shallow Sand Bed):** 2–3 سم — للمظهر فقط، تنظيف سهل.\n\n**DSB (Deep Sand Bed):** 10–15 سم — يخلق طبقات لاهوائية تُقلل النترات. يحتاج اهتماماً وخبرة أكبر.\n\n> للمبتدئ: ابدأ بـ 3–4 سم من الأراغونيت الناعم.\n\n---\n\n## تجهيز الرمل قبل الاستخدام\n\n**للرمل الجاف:**\n1. اشطفه بماء RO/DI حتى يصفو الماء\n2. أضفه للحوض برفق بكيس مثقوب\n\n**للرمل الحي (Live Sand):**\n- يمكن إضافته مباشرةً — يُسرّع النضج\n- أغلى سعراً\n\n---\n\n## الرمل الحي أم الجاف؟\n\nللمبتدئ: الرمل الجاف المُجهَّز جيداً + بكتيريا جاهزة = نفس النتيجة بسعر أقل.\n\n---\n\n## الحيوانات التي تُساعد في نظافة الرمل\n\n- **Nassarius Snails:** تتحرك في الرمل وتُهويه\n- **Sand Sifting Star:** يُقلب الرمل لكن يأكل الحياة الدقيقة\n- **Watchman Gobies:** يحفر ويُنقي الرمل\n\n---\n\n*بقلم زيد العكيلي*',
'إعداد',
'["رمل","aragonite","قاع","تصفية","إعداد"]',
'["dry-rock","bacteria","aquarium-components"]',
'[]',
'',
'رمل حوض البحر: ما تحتاج معرفته قبل الشراء',
'تعرف على أنواع الرمل المناسبة لحوض المياه المالحة وكيف تُعده بشكل صحيح',
false, 5,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'bacteria',
'bacteria',
'البكتيريا المفيدة ودورة النيتروجين: أساس الحياة في الحوض',
'فهم دورة النيتروجين هو أهم خطوة لأي مبتدئ. تعرف على أنواع البكتيريا المفيدة وكيف تُسرّع نضج حوضك بأمان.',
E'## لماذا البكتيريا أساسية؟\n\nكل حوض بحري يعتمد على بكتيريا مفيدة لتحويل نفايات الأسماك السامة إلى مواد أقل ضرراً. بدونها، حوضك بيئة سامة.\n\n---\n\n## دورة النيتروجين\n\nbقايا طعام + نفايات أسماك\n→ الأمونيا (NH3) ← سامة جداً\n→ نتريت (NO2) ← سام (بكتيريا Nitrosomonas)\n→ نترات (NO3) ← أقل سمية (بكتيريا Nitrospira)\n→ نيتروجين (N2) أو استهلاك نباتي (تبديل ماء / DSB)\n\n---\n\n## مراحل النضج البيولوجي\n\n**الأسبوع 1–2:** ترتفع الأمونيا بشكل حاد.\n**الأسبوع 2–4:** تبدأ النتريت في الظهور مع انخفاض تدريجي للأمونيا.\n**الأسبوع 4–8:** تنخفض النتريت ويظهر النترات — الحوض يُشير إلى النضج.\n**بعد ذلك:** قراءة صفر أمونيا وصفر نتريت = الحوض ناضج.\n\n---\n\n## كيف تُسرّع النضج؟\n\n### ١. البكتيريا الجاهزة (Bottled Bacteria)\nأسرع وأموثق طريقة. استخدم منتجات مثل:\n- Dr. Tim''s Aquatics One & Only\n- Fritz TurboStart 900\n- Brightwell Aquatics MicroBacter7\n\nأضف الجرعة الموصى بها ثم أعد إضافتها بعد أسبوع.\n\n### ٢. الصخر الحي\nيُدخل بكتيريا جاهزة ومتنوعة. المخاطرة: احتمال الآفات.\n\n### ٣. مصدر الأمونيا\nالبكتيريا تحتاج "طعاماً". أضف:\n- قطعة روبيان ميت\n- Ammonium Chloride النقي (الأكثر تحكماً)\nالهدف: الحفاظ على 2–4 ppm أمونيا طوال النضج.\n\n### ٤. الدفء\nدرجة حرارة 27–28°C تُسرّع نشاط البكتيريا بشكل ملحوظ.\n\n---\n\n## قراءات دورة النضج\n\n| الوقت | الأمونيا | النتريت | النترات |\n|-------|---------|---------|--------|\n| يوم 1 | ترتفع | 0 | 0 |\n| أسبوع 2 | ذروة | تبدأ | 0 |\n| أسبوع 4 | تنخفض | ذروة | تبدأ |\n| أسبوع 6–8 | 0 | 0 | مرتفع |\n\nعند الوصول لصفر أمونيا وصفر نتريت: افعل تبديل ماء كبير (50%) وابدأ بإضافة الأسماك تدريجياً.\n\n---\n\n## بكتيريا التصدينيتروجين (Denitrification)\n\nهذه بكتيريا لاهوائية تعيش في أعماق الصخر والرمل، تُحوّل النترات إلى نيتروجين غازي.\n- تحتاج: صخور مسامية + رمل عميق (DSB)\n- تعمل ببطء لكن تُقلل النترات طويل الأمد\n\n---\n\n*بقلم زيد العكيلي*',
'بيولوجيا',
'["بكتيريا","نضج","نيتروجين","أمونيا","نتريت","مبتدئين"]',
'["dry-rock","live-rock","water-chemistry"]',
'[]',
'',
'البكتيريا المفيدة ودورة النيتروجين في حوض البحر',
'فهم دورة النيتروجين وكيف تُسرّع نضج حوضك البحري بالبكتيريا المفيدة',
false, 6,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'water-chemistry',
'water-chemistry',
'كيمياء الماء في الحوض البحري: القيم والأسباب',
'KH، كالسيوم، مغنيسيوم، فوسفات، نترات — تعرف على القيم الصحيحة ولماذا يهم كل معامل، مع شرح بسيط لكيفية التصحيح.',
E'## لماذا كيمياء الماء مهمة جداً؟\n\nالشعاب المرجانية حساسة للغاية لتذبذبات الكيمياء. تذبذب مفاجئ في KH بمقدار 1 dKH خلال يوم واحد يمكن أن يُنهار مستعمرة مرجان كاملة.\n\n---\n\n## القيم المرجعية للحوض البحري\n\n| المعامل | القيمة المثالية | الحد الأدنى | الحد الأقصى |\n|---------|----------------|------------|------------|\n| الملوحة (SG) | 1.025–1.026 | 1.023 | 1.027 |\n| الحرارة | 25–26°C | 24°C | 28°C |\n| pH | 8.1–8.3 | 7.9 | 8.5 |\n| KH (العسرة) | 8–9 dKH | 7 | 11 |\n| كالسيوم | 400–450 mg/L | 380 | 480 |\n| مغنيسيوم | 1250–1350 mg/L | 1200 | 1400 |\n| نترات (NO3) | <10 mg/L | 0 | 20 |\n| فوسفات (PO4) | 0.03–0.08 mg/L | 0.02 | 0.1 |\n\n---\n\n## KH (Alkalinity / العسرة)\n\nKH هو "حصن" الـ pH — يُثبّته ويمنع انهياره. المرجان يستهلكه باستمرار لبناء هيكله الكلسي.\n\n**كيف ترفع KH:**\n- محلول بيكربونات الصوديوم (سريع لكن مؤقت)\n- Two-part dosing (جزء A يحتوي KH)\n- Kalkwasser (ماء الجير)\n- **Kh red sea 500ml عسره** — محلول جاهز للجرعة الدقيقة\n\n> :warn: لا ترفع KH بأكثر من 0.5–1 dKH في اليوم لتجنب الصدمة الكيميائية.\n\n---\n\n## الكالسيوم (Ca)\n\nاللبنة الأساسية لهيكل المرجان والقشريات.\n\n**كيف ترفع الكالسيوم:**\n- **كالسيوم سائل ٥٠٠ مل** — محلول سائل مركّز للإضافة اليومية\n- Two-part dosing (الجزء B)\n- Calcium reactor (للأحواض الكبيرة)\n\n> **تذكر:** الكالسيوم والـ KH مترابطان. إذا رفعت أحدهما بشدة ينخفض الآخر.\n\n---\n\n## المغنيسيوم (Mg)\n\nيُمكّن الكالسيوم من البقاء ذائباً. مغنيسيوم منخفض = كالسيوم يترسب على الصخور قبل أن يصل للمرجان.\n\n**كيف ترفع المغنيسيوم:**\n- **Mg مغنيسيوم 500ml** — محلول مركّز لرفع المغنيسيوم تدريجياً\n- ملح Epsom (كبريتات المغنيسيوم) — بديل اقتصادي\n\n---\n\n## النترات والفوسفات\n\nمصادرهما: بقايا طعام، نفايات أسماك، صخر أو رمل قديم.\n\n**كيف تُخفّضهما:**\n- تبديل الماء الأسبوعي (الأسرع والأموثق)\n- Skimmer فعّال\n- GFO (Granular Ferric Oxide) لخفض الفوسفات\n- **NO3PO4-X NoPox** — كربون سائل يُغذي البكتيريا الدينيترفيكاتية لخفض النترات والفوسفات معاً\n\n> :tip: لا تنخفض الفوسفات إلى 0 — المرجان يحتاج كميات صغيرة جداً.\n\n---\n\n## اختبار القيم\n\n**الجدول الأسبوعي للمبتدئ:**\n- النترات + الفوسفات: أسبوعياً\n- KH: أسبوعياً (أو يومياً إذا كان عندك مرجان SPS)\n- الكالسيوم + المغنيسيوم: مرة كل أسبوعين\n- الملوحة: يومياً أو عبر ATO\n\n---\n\n*بقلم زيد العكيلي*',
'كيمياء',
'["kh","كالسيوم","مغنيسيوم","نترات","فوسفات","كيمياء"]',
'["bacteria","aquarium-components","saltwater-preparation"]',
'[{"display_text":"Kh red sea 500ml عسره","product_name":"Kh red sea 500ml عسره"},{"display_text":"كالسيوم سائل ٥٠٠ مل","product_name":"كالسيوم سائل ٥٠٠ مل"},{"display_text":"Mg مغنيسيوم 500ml","product_name":"Mg مغنيسيوم 500ml"},{"display_text":"NO3PO4-X NoPox","product_name":"NO3PO4-X NoPox"}]',
'',
'كيمياء الماء في الحوض البحري: القيم والأسباب',
'تعرف على القيم المثالية لـ KH والكالسيوم والمغنيسيوم والنترات في حوض البحر وكيف تصحح الانحرافات',
false, 7,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'wavemaker',
'wavemaker',
'الـ Wavemaker: لماذا الحركة ضرورية في حوضك؟',
'الحركة في الحوض البحري ليست رفاهية — إنها حاجة حيوية للمرجان والأسماك. تعرف على كيفية اختيار الـ Wavemaker المناسب وكيفية ضبطه.',
E'## لماذا تحتاج Wavemaker؟\n\nفي الشعاب الطبيعية، التيارات المائية لا تتوقف أبداً. هذه الحركة:\n- **تُوصّل الغذاء** للمرجان الذي لا يستطيع التحرك\n- **تُهوّي الماء** وتُساعد على التبادل الغازي (O2/CO2)\n- **تمنع البقع الراكدة** حيث يتراكم الديترايتس والطحالب\n- **تُحاكي موجة البحر** التي يتكيف معها المرجان\n\n---\n\n## أنواع Wavemakers\n\n### ١. Powerhead بسيط\nمضخة تعمل بشكل مستمر. رخيصة، لكن لا تُنتج حركة طبيعية متغيرة.\n\n### ٢. Wavemaker مع تحكم\nيتبع أنماطاً متغيرة: موجة، نبض، عشوائي. الأفضل للمرجان.\n\n### ٣. Propeller Pump (مروحة)\nتُنتج حجم ماء كبير بضغط منخفض — مثالي لأحواض المرجان.\n\n---\n\n## كيف تختار الحجم المناسب؟\n\nالقاعدة العامة: تُريد **10–50 ضعف حجم الحوض** من الحركة في الساعة.\n\n**مثال:** حوض 300 لتر → تحتاج 3000–15000 لتر/ساعة حركة.\n\n- أحواض أسماك فقط: 10–20 ضعف\n- أحواض LPS: 20–30 ضعف\n- أحواض SPS: 30–50 ضعف\n\n---\n\n## ReefWAVE من Red Sea\n\nخط ReefWAVE يُقدم تحكماً ذكياً عبر تطبيق Red Sea App:\n\n| الموديل | الحجم الأقصى | مناسب لـ |\n|---------|-------------|----------|\n| ReefWAVE 25 | 25000 L/hr | أحواض 200–500L |\n| ReefWAVE 45 | 45000 L/hr | أحواض 400–900L |\n\n**مميزات ReefWAVE:**\n- تحكم عبر التطبيق مع 6 أنماط حركة\n- Lagoon Mode / Reef Crest Mode / Nutrient Transport Mode\n- صامت تقريباً\n- مغناطيس تثبيت قوي مع حماية خزفية للشفرات\n\n---\n\n## مكان التثبيت\n\n- **لا تُثبّت مباشرة نحو المرجان** — تيار مباشر يُتلف أنسجته\n- ثبّته على جوانب الحوض موجهاً نحو المنتصف\n- استخدم Wavemakers في الزوايا المتقابلة لإنشاء حركة متصادمة طبيعية\n- ارفعه عن القاع لمنع رفع الرمل\n\n---\n\n## برمجة الـ Wavemaker\n\n**للمبتدئ:** ابدأ بـ 30–40% من الطاقة القصوى وزد تدريجياً مراقباً استجابة المرجان.\n\n**علامات أن الحركة قوية جداً:**\n- المرجان يُعيد شعيراته إلى الداخل\n- الرمل يتطاير باستمرار\n- الأسماك تكافح للسباحة\n\n**علامات أن الحركة ضعيفة:**\n- تراكم الديترايتس على الصخور\n- المرجان لا يتمدد جيداً\n- طحالب تنمو في زوايا راكدة\n\n---\n\n*بقلم زيد العكيلي*',
'معدات',
'["wavemaker","حركة","تيار","مرجان","ReefWave"]',
'["aquarium-components","lighting","return-pump"]',
'[{"display_text":"ReefWAVE 25","product_name":"ReefWAVE 25"},{"display_text":"ReefWAVE 45","product_name":"ReefWAVE 45"}]',
'',
'الـ Wavemaker: لماذا الحركة ضرورية في حوضك البحري؟',
'اختر الـ Wavemaker المناسب لحوضك البحري وتعلم كيف تضبطه لصحة المرجان',
false, 8,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'uv-sterilizer',
'uv-sterilizer',
'جهاز UV Sterilizer: هل يحتاجه حوضك؟',
'جهاز تعقيم الأشعة فوق البنفسجية — متى يُفيد حقاً، متى يضر، وكيف تُثبّته وتُشغّله بشكل صحيح.',
E'## ما هو الـ UV Sterilizer؟\n\nجهاز UV Sterilizer هو وحدة تمر فيها مياه الحوض أمام مصباح أشعة فوق بنفسجية. هذه الأشعة تُدمر DNA الكائنات الدقيقة المارة بها:\n- البكتيريا الضارة العائمة\n- الطفيليات أحادية الخلية (مثل Ich و Velvet)\n- الطحالب الدقيقة (Green Water)\n- الفيروسات (بدرجة محدودة)\n\n---\n\n## هل هو ضروري؟\n\n**ليس أساسياً** في الحوض المستقر الصحي — لكنه مفيد جداً في:\n- أحواض حجر عزل جديدة أو بعد إضافة سمك جديد\n- الأحواض التي تعاني تكرار أمراض\n- بعد علاج مرض للقضاء على بقايا الطفيليات\n- الأحواض ذات الكثافة العالية من الأسماك\n\n---\n\n## ما لا يفعله الـ UV\n\n- لا يُعالج مرضاً موجوداً داخل جسم السمكة\n- لا يُعقّم الصخور والرمل — يعمل فقط على الماء العابر\n- لا يُقلل النترات أو الفوسفات\n- لا يُعوّض عن نظام التصفية\n\n---\n\n## كيف يعمل بشكل فعّال؟\n\nفاعلية الـ UV تعتمد على **معدل تدفق الماء** عبره:\n\n| الهدف | معدل التدفق |\n|-------|-------------|\n| قتل البكتيريا | سريع (أعلى التوصيات) |\n| قتل الطفيليات | متوسط |\n| قتل طحالب الماء الأخضر | بطيء (أقل التوصيات) |\n\n**الخلاصة:** معدل تدفق أبطأ = تعقيم أعمق.\n\n---\n\n## التثبيت الصحيح\n\n- اربطه **بعد** الفلتر الميكانيكي — الماء العكر يُضعف الأشعة\n- **لا تُثبّته قبل** Skimmer أو Refugium\n- اجعل الماء يمر فيه بانتظام، ليس كل الماء دفعة واحدة\n- استبدل المصباح كل **6–12 شهر** حتى لو لا يزال يعمل — الأشعة تضعف قبل أن ينطفئ الضوء\n\n---\n\n## متى تُشغّله؟\n\n**تشغيل 24/7:** عند:\n- وجود سمك جديد في العزل\n- بعد اكتشاف مرض\n- وقاية مستمرة\n\n**إيقافه مؤقتاً عند:**\n- إضافة بكتيريا جاهزة (UV يقتلها!)\n- إضافة أدوية حيوية للحوض\n- استخدام Phytoplankton أو Pods\n\n---\n\n## التحذيرات\n\n> :warn: لا تنظر مباشرةً إلى مصباح UV المشتغل — يُسبب أذى للعينين والجلد.\n> :warn: لا تُشغّله خارج الماء — المصباح يسخن ويُتلف.\n\n---\n\n*بقلم زيد العكيلي*',
'معدات',
'["UV","تعقيم","أمراض","طفيليات","صحة أسماك"]',
'["aquarium-components","bacteria"]',
'[]',
'',
'جهاز UV Sterilizer لحوض البحر: هل تحتاجه؟',
'تعرف على جهاز تعقيم الأشعة فوق البنفسجية ومتى يفيد حوضك البحري',
false, 9,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'lighting',
'lighting',
'إضاءة حوض البحر: الدليل الكامل لاختيار الـ LED',
'الإضاءة هي الفرق بين مرجان مزهر وآخر يحتضر. تعرف على مفاهيم PAR و PUR و spectrum واختر الإضاءة المناسبة لنظامك.',
E'## لماذا الإضاءة مختلفة في الحوض البحري؟\n\nالمرجان يحتوي على طحالب مجهرية تُسمى Zooxanthellae تعيش داخل أنسجته وتُوفّر له 80–90% من غذائه عبر التمثيل الضوئي. بدون إضاءة مناسبة، تطرد المرجان هذه الطحالب — وهذا ما نُسميه **"التبييض" (Bleaching)**.\n\n---\n\n## المفاهيم الأساسية\n\n### PAR (Photosynthetically Active Radiation)\nمقياس كمية الضوء المفيد للتمثيل الضوئي. يُقاس بـ µmol/m²/s.\n\n| نوع المرجان | PAR المطلوب |\n|------------|------------|\n| LPS (Hammer، Frogspawn) | 50–150 |\n| Soft Coral | 50–100 |\n| SPS (Acropora، Montipora) | 200–400+ |\n| Clams | 200–400 |\n\n### Spectrum (الطيف)\nالمرجان يستخدم بشكل خاص:\n- **الأزرق (420–480 nm)** — الأهم للـ Zooxanthellae\n- **الأخضر والأحمر** — للنباتات والطحالب المفيدة\n\n### Photoperiod (مدة الإضاءة)\nابدأ بـ **8–10 ساعات/يوم**. قليل جداً يُضعف المرجان. كثير جداً يُشجع الطحالب.\n\n---\n\n## أنواع إضاءة LED للحوض البحري\n\n### ١. LED أحادية الشريط (Strip LED)\nرخيصة، للأسماك فقط — لا تكفي للمرجان.\n\n### ٢. LED كاملة الطيف مع تحكم\nالمعيار الحديث للأحواض البحرية المتقدمة:\n- تحكم في كل قناة لونية\n- برمجة شروق/غروب تدريجي\n- تطبيق للتحكم اللاسلكي\n\n---\n\n## ReefLED G2 من Red Sea\n\nخط ReefLED G2 الأحدث يوفر أداءً احترافياً:\n\n| الموديل | تغطية | مثالي لـ |\n|---------|--------|----------|\n| ReefLED G2 60 | حوض 60×60 سم | أحواض نانو وصغيرة |\n| ReefLED G2 115 | حوض 90–120 سم | أحواض متوسطة |\n| ReefLED G2 170 | حوض 120–150 سم | أحواض كبيرة |\n\n**مميزات ReefLED G2:**\n- طيف محسّن مع قنوات UV و Violet و Blue و White\n- تحكم عبر تطبيق Red Sea App\n- تقنية MyColors لتخصيص اللون\n- كفاءة طاقة عالية\n- نظام تبريد صامت\n\n---\n\n## برمجة الإضاءة\n\n**مثال جدول يومي:**\n\n| الوقت | الحالة |\n|-------|--------|\n| 6:00 صباحاً | بداية تدريجية (10%) |\n| 9:00 صباحاً | 70% أزرق، 50% أبيض |\n| 12:00 ظهراً | ذروة (100% أزرق، 70% أبيض) |\n| 4:00 مساءً | بدء التراجع التدريجي |\n| 8:00 مساءً | 10% أزرق فقط |\n| 10:00 مساءً | إيقاف كامل |\n\n---\n\n## أخطاء شائعة في الإضاءة\n\n- **زيادة الشدة فجأة:** يُصدم المرجان ويُبيّض. زد الشدة تدريجياً على أسابيع.\n- **إضاءة زرقاء فقط:** جميلة بصرياً لكن المرجان يحتاج طيفاً كاملاً.\n- **مسافة خاطئة:** المصباح قريب جداً = PAR مرتفع جداً. ابعده أو خفّف الشدة.\n- **لا برمجة:** إضاءة ثابتة 24/7 تُجهد المرجان وتُشجع الطحالب.\n\n---\n\n*بقلم زيد العكيلي*',
'إضاءة',
'["LED","PAR","مرجان","ReefLED","إضاءة","SPS","LPS"]',
'["aquarium-components","wavemaker","water-chemistry"]',
'[{"display_text":"ReefLED G2 60","product_name":"ReefLED G2 60"},{"display_text":"ReefLED G2 115","product_name":"ReefLED G2 115"},{"display_text":"ReefLED G2 170","product_name":"ReefLED G2 170"}]',
'',
'إضاءة حوض البحر: الدليل الكامل لاختيار الـ LED',
'تعلم كيف تختار إضاءة LED مناسبة لحوضك البحري وتُبرمجها لصحة المرجان',
false, 10,
NOW(), NOW()
);

INSERT INTO reference_topics (id, slug, title, excerpt, content_markdown, category, tags, related_topics, product_links, image, seo_title, meta_description, hidden, sort_order, created_at, updated_at) VALUES (
'return-pump',
'return-pump',
'مضخة الإرجاع (Return Pump): قلب نظام تدوير الماء',
'مضخة الإرجاع هي العمود الفقري لدورة الماء بين الحوض الرئيسي والـ Sump. تعرف على كيفية اختيارها وضبطها وصيانتها.',
E'## ما هي مضخة الإرجاع؟\n\nمضخة الإرجاع (Return Pump) هي المضخة المسؤولة عن رفع الماء من الـ Sump الأسفل إلى الحوض الرئيسي الأعلى. هي الدورة الدموية الرئيسية لحوضك.\n\nبدونها:\n- يتوقف تدفق الماء عبر الـ Skimmer\n- يتوقف عمل الـ Refugium\n- تنقطع التصفية الميكانيكية والبيولوجية\n\n---\n\n## كيف تختار الحجم المناسب؟\n\n### احسب "الارتفاع الكلي" (Head Pressure)\nكلما ارتفع الحوض عن الـ Sump، كلما احتجت ضخاً أقوى.\n\n**المعادلة البسيطة:**\n- 1 متر ارتفاع = خسارة ~25% من القدرة\n- الأنابيب والمرفقات = خسارة إضافية\n\n**الهدف:** معدل تبادل **5–10 أضعاف** حجم الحوض الكلي في الساعة.\n\n**مثال:** حوض 300L + Sump 100L = 400L إجمالي → تحتاج 2000–4000 L/hr عند الارتفاع الفعلي.\n\n---\n\n## ReefRun G2 — المضخة الذكية\n\nالـ ReefRun G2 12000 هي مضخة DC (تيار مستمر) بتحكم رقمي:\n\n| المواصفة | القيمة |\n|----------|--------|\n| أقصى تدفق | 12000 L/hr |\n| أقصى ارتفاع | 8 متر |\n| الاستهلاك | 85W |\n| التحكم | تطبيق Red Sea App |\n\n**مميزات ReefRun G2:**\n- تحكم في السرعة من 1–100%\n- وضع "الغذاء" يُوقف المضخة مؤقتاً\n- وضع الطوارئ عند تراجع منسوب الـ Sump\n- رأس محرك قابل للفك للتنظيف السهل\n- ضمان 3 سنوات\n\n---\n\n## أنواع مضخات الإرجاع\n\n### AC (تيار متردد)\n- أرخص سعراً\n- أقل كفاءة طاقوية\n- لا تحكم في السرعة\n- مناسبة للميزانية المحدودة\n\n### DC (تيار مستمر)\n- تحكم كامل في السرعة\n- أكثر كفاءة\n- أهدأ صوتاً\n- سعر أعلى لكن توفير في الكهرباء\n\n---\n\n## الصيانة الدورية\n\n**شهرياً:**\n- نظّف فتحة الدخول من الطحالب والترسبات\n- افحص الأنابيب المتصلة\n\n**كل 3–6 أشهر:**\n- فكّ رأس المضخة ونظّفه بمحلول خل أبيض لإزالة الكالسيوم\n- افحص المحرك (impeller) من الكسر أو الاتساخ\n\n**علامات أن المضخة تحتاج صيانة:**\n- صوت اهتزاز غير مألوف\n- تراجع في تدفق الماء\n- ارتفاع في استهلاك الكهرباء\n\n---\n\n## نصائح التثبيت\n\n- استخدم خرطوم مرن عند التوصيل بالحوض الرئيسي لامتصاص الاهتزاز\n- أضف **صمام عدم رجوع (Check Valve)** لمنع الماء من الرجوع عند الإيقاف\n- لا تضع المضخة في أعمق نقطة من الـ Sump — اتركها معلّقة أو على حامل\n- احتفظ دائماً بمضخة احتياطية (حتى لو صغيرة) لحالات الطوارئ\n\n---\n\n*بقلم زيد العكيلي*',
'معدات',
'["return pump","مضخة","sump","ReefRun","تدوير"]',
'["aquarium-components","wavemaker","uv-sterilizer"]',
'[{"display_text":"ReefRun G2 12000","product_name":"ReefRun G2 12000"}]',
'',
'مضخة الإرجاع Return Pump: قلب نظام تدوير الماء',
'اختر مضخة الإرجاع المناسبة لحوضك البحري وتعلم كيف تُثبّتها وتُصونها',
false, 11,
NOW(), NOW()
);
